from dataclasses import dataclass, field
from datetime import date

@dataclass
class PromptPatch:
    patch_id: str
    date_applied: date
    reason: str            # what behaviour necessitated this patch
    instruction_added: str # the instruction text that was added
    model_version_at_patch: str
    still_relevant: bool | None = None  # None = not yet reviewed

    def possibly_stale(self, current_model_version: str) -> bool:
        """
        Patches applied against an older model version may be addressing
        behaviour that has changed. Flag them for review.
        """
        return self.model_version_at_patch != current_model_version and self.still_relevant is None

@dataclass
class PromptDebtRecord:
    system_prompt_version: str
    last_full_refactor_date: date | None
    patches: list[PromptPatch] = field(default_factory=list)

    def patch_count(self) -> int:
        return len(self.patches)

    def stale_patch_count(self, current_model_version: str) -> int:
        return sum(1 for p in self.patches if p.possibly_stale(current_model_version))

    def refactor_urgency(self, today: date, current_model_version: str) -> str:
        if self.patch_count() > 10:
            return "HIGH: >10 patches without refactor — structural integrity at risk"
        if self.stale_patch_count(current_model_version) > 3:
            return "HIGH: >3 stale patches — verify behaviour after model update"
        days_since = (today - self.last_full_refactor_date).days if self.last_full_refactor_date else 9999
        if days_since > 90:
            return "MEDIUM: >90 days since last refactor — schedule refactor sprint"
        return "LOW: prompt in acceptable state"

from dataclasses import dataclass, field
from datetime import date

@dataclass
class TechDebtRegister:
    integration_name: str
    records: list[TechDebtRecord] = field(default_factory=list)

    def add(self, record: TechDebtRecord) -> None:
        self.records.append(record)

    def open_records(self) -> list[TechDebtRecord]:
        return [r for r in self.records if not r.resolved]

    def by_category(self, category: DebtCategory) -> list[TechDebtRecord]:
        return [r for r in self.open_records() if r.category == category]

    def high_impact_open(self) -> list[TechDebtRecord]:
        return [r for r in self.open_records() if r.impact == DebtImpact.HIGH]

    def overdue_open(self, today: date) -> list[TechDebtRecord]:
        return [r for r in self.open_records() if r.is_overdue(today)]

    def category_breakdown(self) -> dict[str, int]:
        breakdown = {}
        for r in self.open_records():
            breakdown[r.category.value] = breakdown.get(r.category.value, 0) + 1
        return breakdown

    def register_health(self, today: date) -> str:
        high_open = self.high_impact_open()
        overdue = self.overdue_open(today)
        issues = []
        if high_open:
            issues.append(f"{len(high_open)} high-impact items open")
        if overdue:
            issues.append(f"{len(overdue)} items overdue")
        breakdown = self.category_breakdown()
        dominant = max(breakdown, key=breakdown.get) if breakdown else None
        if dominant and breakdown.get(dominant, 0) > 5:
            issues.append(f"prompt debt accumulating ({breakdown[dominant]} open items)" if dominant == "prompt" else f"{dominant} debt high ({breakdown[dominant]} open)")
        if not issues:
            return "HEALTHY"
        return "NEEDS ATTENTION: " + "; ".join(issues)

from dataclasses import dataclass, field
from datetime import date

@dataclass
class QuarterlyDebtReview:
    review_date: date
    integration_name: str
    register_snapshot: "TechDebtRegister"

    # Filled in during review
    category_trends: dict[str, str] = field(default_factory=dict)
    # e.g. {"prompt": "increasing", "integration": "stable", "test": "decreasing"}

    strategic_investments: list[str] = field(default_factory=list)
    # Items that require a dedicated effort beyond normal sprint allocation

    reprioritised_items: list[tuple[str, str, str]] = field(default_factory=list)
    # List of (debt_id, old_priority, new_priority)

    items_closed_wont_fix: list[str] = field(default_factory=list)
    next_review_date: date = None

    def open_high_impact_count(self) -> int:
        return len(self.register_snapshot.high_impact_open())

    def total_open_count(self) -> int:
        return len(self.register_snapshot.open_records())

    def review_summary(self) -> str:
        lines = [
            f"Quarterly debt review: {self.integration_name} ({self.review_date})",
            f"Open items: {self.total_open_count()} ({self.open_high_impact_count()} high-impact)",
            f"Reprioritised: {len(self.reprioritised_items)}",
            f"Closed as won't-fix: {len(self.items_closed_wont_fix)}",
            f"Strategic investments identified: {len(self.strategic_investments)}",
        ]
        for category, trend in self.category_trends.items():
            lines.append(f"  {category}: {trend}")
        return "\n".join(lines)
